#!/usr/bin/env node
/**
 * Build script: convert TTF font files in this directory to embedded base64
 * JS files. Needed so PDF export works when the webapp is opened directly via
 * file:// (where fetch/XHR of local binaries is blocked by browsers).
 *
 * Usage:  node build_font_embed.js
 *
 * Outputs:  NotoSansSC-Regular.font.js  (~14 MB)
 *           NotoSansSC-Bold.font.js     (~14 MB)
 *
 * The generated .font.js files register base64 strings on window.__EMBEDDED_FONTS.
 * Loaded via <script> tags which work under file:// (unlike fetch).
 */

var fs = require("fs");
var path = require("path");

var SOURCES = [
  "NotoSansSC-Regular.ttf",
  "NotoSansSC-Bold.ttf"
];

var here = __dirname;

SOURCES.forEach(function (ttf) {
  var src = path.join(here, ttf);
  if (!fs.existsSync(src)) {
    console.error("Missing: " + src);
    return;
  }
  var bytes = fs.readFileSync(src);
  var b64 = bytes.toString("base64");
  var outName = ttf.replace(/\.ttf$/i, ".font.js");
  var outPath = path.join(here, outName);
  var js =
    "// Auto-generated by build_font_embed.js — do not edit.\n" +
    "// Source: " + ttf + "\n" +
    "(function () {\n" +
    "  window.__EMBEDDED_FONTS = window.__EMBEDDED_FONTS || {};\n" +
    "  window.__EMBEDDED_FONTS[" + JSON.stringify(ttf) + "] = " + JSON.stringify(b64) + ";\n" +
    "})();\n";
  fs.writeFileSync(outPath, js, "utf-8");
  console.log("Wrote " + outName + " (" + b64.length + " base64 chars)");
});
